## 5. gRPC Proto 설계

```protobuf
// protobuf/src/main/proto/notification/notification_service.proto

syntax = "proto3";
package notification;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.notification";

service NotificationService {
  // 알림 발송 (다른 서비스에서 호출)
  rpc CreateNotification(CreateNotificationRequest) returns (CreateNotificationResponse);

  // 알림 목록 조회
  rpc ListNotifications(ListNotificationsRequest) returns (ListNotificationsResponse);

  // 단일 알림 읽음 처리
  rpc UpdateNotificationRead(UpdateNotificationReadRequest) returns (UpdateNotificationReadResponse);

  // 전체 읽음 처리
  rpc UpdateAllNotificationsRead(UpdateAllNotificationsReadRequest) returns (UpdateAllNotificationsReadResponse);

  // 읽지 않은 알림 수 조회
  rpc GetUnreadCount(GetUnreadCountRequest) returns (GetUnreadCountResponse);

  // 디바이스 토큰 등록/갱신
  rpc CreateDeviceToken(CreateDeviceTokenRequest) returns (CreateDeviceTokenResponse);

  // 디바이스 토큰 삭제 (로그아웃 시)
  rpc DeleteDeviceToken(DeleteDeviceTokenRequest) returns (DeleteDeviceTokenResponse);

  // 알림 설정 조회
  rpc GetNotificationSetting(GetNotificationSettingRequest) returns (GetNotificationSettingResponse);

  // 알림 설정 수정
  rpc UpdateNotificationSetting(UpdateNotificationSettingRequest) returns (UpdateNotificationSettingResponse);
}

// ---- 알림 메시지 타입 ----
enum NotificationType {
  NOTIFICATION_TYPE_UNSPECIFIED = 0;
  CALL_INCOMING = 1;
  CALL_MISSED = 2;
  MESSAGE_RECEIVED = 3;
  FOLLOW_NEW = 4;
  FOLLOW_REQUEST = 5;
  MOMENT_LIKE = 6;
  MOMENT_COMMENT = 7;
}

// ---- 공통 메시지 ----
message Notification {
  string id = 1;
  string recipient_id = 2;
  optional string sender_id = 3;
  NotificationType type = 4;
  string title = 5;
  string body = 6;
  optional string payload = 7;
  bool is_read = 8;
  string created_at = 9;
}

// ---- CreateNotification ----
message CreateNotificationRequest {
  string recipient_id = 1;
  optional string sender_id = 2;
  NotificationType type = 3;
  string title = 4;
  string body = 5;
  optional string payload = 6;
}

message CreateNotificationResponse {
  Notification notification = 1;
}

// ---- ListNotifications ----
message ListNotificationsRequest {
  string user_id = 1;
  optional int32 limit = 2;
  optional string cursor = 3;   // 커서 기반 페이징
}

message ListNotificationsResponse {
  repeated Notification notifications = 1;
  optional string next_cursor = 2;
}

// ---- UpdateNotificationRead ----
message UpdateNotificationReadRequest {
  string notification_id = 1;
  string user_id = 2;
}

message UpdateNotificationReadResponse {
  bool success = 1;
